import React, { useState, useEffect } from 'react'
import { toast } from 'react-hot-toast'
import { 
  Printer, 
  Plus, 
  Save, 
  X, 
  CheckCircle, 
  AlertCircle, 
  Calendar,
  TrendingUp,
  Activity,
  Clock
} from 'lucide-react'
import { machinesAPI } from '../services/api'
import reminderService from '../services/reminderService'

const MachineCountEntry = ({ onClose, onSave }) => {
  const [machines, setMachines] = useState([])
  const [readings, setReadings] = useState({})
  const [loading, setLoading] = useState(false)
  const [saving, setSaving] = useState(false)
  const [selectedDate, setSelectedDate] = useState(new Date().toISOString().split('T')[0])

  useEffect(() => {
    fetchMachines()
  }, [])

  const fetchMachines = async () => {
    try {
      setLoading(true)
      const response = await machinesAPI.getAll()
      const machineList = response.data || []
      
      // Initialize readings for each machine
      const initialReadings = {}
      machineList.forEach(machine => {
        initialReadings[machine._id] = {
          previousCount: 0,
          currentCount: 0,
          notes: ''
        }
      })
      
      setMachines(machineList)
      setReadings(initialReadings)
    } catch (error) {
      console.error('Error fetching machines:', error)
      toast.error('Failed to load machines')
    } finally {
      setLoading(false)
    }
  }

  const handleReadingChange = (machineId, field, value) => {
    setReadings(prev => ({
      ...prev,
      [machineId]: {
        ...prev[machineId],
        [field]: field === 'currentCount' ? parseInt(value) || 0 : value
      }
    }))
  }

  const calculatePrints = (machineId) => {
    const reading = readings[machineId]
    if (!reading) return 0
    return Math.max(0, reading.currentCount - reading.previousCount)
  }

  const validateReadings = () => {
    let errors = []
    
    Object.entries(readings).forEach(([machineId, reading]) => {
      if (reading.currentCount < reading.previousCount) {
        const machine = machines.find(m => m._id === machineId)
        errors.push(`${machine?.name || 'Machine'}: Current count cannot be less than previous count`)
      }
    })
    
    return errors
  }

  const handleSave = async () => {
    const errors = validateReadings()
    
    if (errors.length > 0) {
      toast.error('Please fix the following errors:\n' + errors.join('\n'))
      return
    }

    try {
      setSaving(true)
      
      // Prepare readings data for API
      const readingsData = Object.entries(readings).map(([machineId, reading]) => ({
        machineId,
        date: selectedDate,
        previousCount: reading.previousCount,
        currentCount: reading.currentCount,
        printsCount: calculatePrints(machineId),
        notes: reading.notes
      }))

      // In a real implementation, you would save to your API
      // await machinesAPI.saveReadings(readingsData)
      
      // Mark machine counts as entered for today
      reminderService.markMachineCountsEntered()
      
      // Show success message
      const totalPrints = readingsData.reduce((sum, reading) => sum + reading.printsCount, 0)
      toast.success(`Successfully saved ${readingsData.length} machine readings! Total prints: ${totalPrints}`)
      
      // Call onSave callback if provided
      if (onSave) {
        onSave(readingsData)
      }
      
      // Close modal
      onClose()
      
    } catch (error) {
      console.error('Error saving readings:', error)
      toast.error('Failed to save readings')
    } finally {
      setSaving(false)
    }
  }

  const getTotalPrints = () => {
    return Object.keys(readings).reduce((total, machineId) => {
      return total + calculatePrints(machineId)
    }, 0)
  }

  const getCompletedMachines = () => {
    return Object.values(readings).filter(reading => reading.currentCount > 0).length
  }

  if (loading) {
    return (
      <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
        <div className="bg-white rounded-lg p-8 flex items-center">
          <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600 mr-3"></div>
          <span className="text-gray-700">Loading machines...</span>
        </div>
      </div>
    )
  }

  return (
    <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
      <div className="bg-white rounded-lg shadow-2xl max-w-4xl w-full max-h-[90vh] overflow-hidden">
        {/* Header */}
        <div className="bg-gradient-to-r from-blue-600 to-indigo-600 text-white p-6">
          <div className="flex items-center justify-between">
            <div className="flex items-center">
              <Printer className="h-6 w-6 mr-3" />
              <div>
                <h3 className="text-xl font-semibold">Daily Machine Count Entry</h3>
                <p className="text-blue-100 text-sm">Record today's machine readings</p>
              </div>
            </div>
            <button
              onClick={onClose}
              className="text-white hover:text-gray-200 transition-colors"
            >
              <X className="h-6 w-6" />
            </button>
          </div>
        </div>

        {/* Date Selection */}
        <div className="bg-gray-50 border-b border-gray-200 p-4">
          <div className="flex items-center space-x-4">
            <label className="text-sm font-medium text-gray-700">Date:</label>
            <input
              type="date"
              value={selectedDate}
              onChange={(e) => setSelectedDate(e.target.value)}
              className="px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
              max={new Date().toISOString().split('T')[0]}
            />
            <div className="flex items-center space-x-4 text-sm text-gray-600">
              <span className="flex items-center">
                <CheckCircle className="h-4 w-4 text-green-500 mr-1" />
                {getCompletedMachines()}/{machines.length} Completed
              </span>
              <span className="flex items-center">
                <TrendingUp className="h-4 w-4 text-blue-500 mr-1" />
                {getTotalPrints()} Total Prints
              </span>
            </div>
          </div>
        </div>

        {/* Machine Readings */}
        <div className="p-6 overflow-y-auto max-h-[60vh]">
          <div className="space-y-4">
            {machines.map((machine) => {
              const reading = readings[machine._id] || {}
              const prints = calculatePrints(machine._id)
              
              return (
                <div key={machine._id} className="bg-gray-50 rounded-lg p-4 border border-gray-200">
                  <div className="flex items-center justify-between mb-3">
                    <div className="flex items-center">
                      <Printer className="h-5 w-5 text-gray-600 mr-2" />
                      <div>
                        <h4 className="font-medium text-gray-900">{machine.name}</h4>
                        <p className="text-sm text-gray-500">{machine.brand} {machine.modelNumber}</p>
                      </div>
                    </div>
                    {prints > 0 && (
                      <div className="flex items-center bg-green-100 text-green-800 px-3 py-1 rounded-full">
                        <Activity className="h-4 w-4 mr-1" />
                        <span className="text-sm font-medium">{prints} prints</span>
                      </div>
                    )}
                  </div>
                  
                  <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Previous Count</label>
                      <input
                        type="number"
                        value={reading.previousCount || 0}
                        onChange={(e) => handleReadingChange(machine._id, 'previousCount', e.target.value)}
                        className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                        placeholder="0"
                      />
                    </div>
                    
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Current Count</label>
                      <input
                        type="number"
                        value={reading.currentCount || 0}
                        onChange={(e) => handleReadingChange(machine._id, 'currentCount', e.target.value)}
                        className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                        placeholder="0"
                      />
                    </div>
                    
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Prints Today</label>
                      <div className="w-full px-3 py-2 bg-blue-50 border border-blue-200 rounded-lg">
                        <span className="text-blue-700 font-medium">{prints}</span>
                      </div>
                    </div>
                    
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Notes</label>
                      <input
                        type="text"
                        value={reading.notes || ''}
                        onChange={(e) => handleReadingChange(machine._id, 'notes', e.target.value)}
                        className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                        placeholder="Optional notes..."
                      />
                    </div>
                  </div>
                </div>
              )
            })}
          </div>
        </div>

        {/* Footer */}
        <div className="bg-gray-50 border-t border-gray-200 p-6">
          <div className="flex items-center justify-between">
            <div className="text-sm text-gray-600">
              <Clock className="h-4 w-4 inline mr-1" />
              Last entry: {new Date().toLocaleString()}
            </div>
            <div className="flex space-x-3">
              <button
                onClick={onClose}
                className="px-6 py-2 border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50 transition-colors"
              >
                Cancel
              </button>
              <button
                onClick={handleSave}
                disabled={saving}
                className="px-6 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors disabled:opacity-50 disabled:cursor-not-allowed flex items-center"
              >
                {saving ? (
                  <>
                    <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-white mr-2"></div>
                    Saving...
                  </>
                ) : (
                  <>
                    <Save className="h-4 w-4 mr-2" />
                    Save Readings
                  </>
                )}
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  )
}

export default MachineCountEntry
